const body = $input.item.json.body ?? $input.item.json;
const rawOutput = body.raw_output;
const outputType = body.output_type;
const brandVoice = body.brand_voice ?? {};

const validTypes = ['intake', 'strategy', 'content', 'automation'];
if (!validTypes.includes(outputType)) {
  throw new Error(`Invalid output_type '${outputType}'. Must be one of: ${validTypes.join(', ')}`);
}
if (!rawOutput) throw new Error('raw_output is required');

const schemaMap = {
  intake: ['company_name', 'niche', 'icp_summary', 'core_offer', 'tone', 'profile_complete', 'fields_missing'],
  strategy: ['gtm_summary', 'icp', 'offer', 'strategy_score', 'first_90_days', 'niche_validated'],
  content: ['content_type'],
  automation: ['draft_meta', 'workflow_json']
};

return [{ json: { raw_output: rawOutput, output_type: outputType, brand_voice: brandVoice, expected_schema: schemaMap[outputType] } }];

