parameters.jsCode:
const raw = $input.item.json;

let text = '';
if (raw.content && Array.isArray(raw.content)) {
  text = raw.content.filter(b => b.type === 'text').map(b => b.text).join('');
} else {
  throw new Error('Unexpected Claude response shape');
}

const cleaned = text.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/```\s*$/i, '').trim();

let result;
try {
  result = JSON.parse(cleaned);
} catch (e) {
  // QA itself failed to parse — treat as structural failure, approve with warning
  result = {
    passed: false,
    score: 40,
    issues: [{ field: 'structure', issue: 'QA agent could not parse its own response: ' + e.message, severity: 'block' }],
    recommendation: 'retry',
    block_reasons: ['QA parse failure'],
    warnings: []
  };
}

const required = ['passed', 'score', 'recommendation'];
for (const k of required) {
  if (!(k in result)) result[k] = k === 'score' ? 50 : k === 'recommendation' ? 'retry' : false;
}

return [{ json: result }];
